export function seedTEU(db) {
    console.log('  Seeding TEU (55 articles)...');
    const insertAct = db.prepare(`INSERT INTO eu_acts (title, short_title, celex_number, act_type, official_journal_ref, adoption_date, entry_into_force_date, status, subject_matter, legal_basis, url)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`);
    const insertArticle = db.prepare(`INSERT INTO articles (act_id, article_number, title, content, part, chapter, section)
     VALUES (?, ?, ?, ?, ?, ?, ?)`);
    const result = insertAct.run('Consolidated version of the Treaty on European Union', 'TEU', '12012M/TXT', 'treaty', 'OJ C 326, 26.10.2012', '1992-02-07', '1993-11-01', 'in_force', 'Constitutional treaty establishing the European Union, its values, objectives, and institutional framework', null, 'https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=celex%3A12012M%2FTXT');
    const actId = result.lastInsertRowid;
    const articles = [
        // PREAMBLE is not an article but we include it as reference
        // TITLE I — COMMON PROVISIONS (Articles 1-8)
        { num: '1', title: 'Establishment of the European Union', content: 'By this Treaty, the HIGH CONTRACTING PARTIES establish among themselves a EUROPEAN UNION, hereinafter called "the Union", on which the Member States confer competences to attain objectives they have in common. This Treaty marks a new stage in the process of creating an ever closer union among the peoples of Europe, in which decisions are taken as openly as possible and as closely as possible to the citizen. The Union shall be founded on the present Treaty and on the Treaty on the Functioning of the European Union. Those two Treaties shall have the same legal value. The Union shall replace and succeed the European Community.', part: 'Title I', chapter: null, section: null },
        { num: '2', title: 'Values of the Union', content: 'The Union is founded on the values of respect for human dignity, freedom, democracy, equality, the rule of law and respect for human rights, including the rights of persons belonging to minorities. These values are common to the Member States in a society in which pluralism, non-discrimination, tolerance, justice, solidarity and equality between women and men prevail.', part: 'Title I', chapter: null, section: null },
        { num: '3', title: 'Aims of the Union', content: '1. The Union\'s aim is to promote peace, its values and the well-being of its peoples.\n2. The Union shall offer its citizens an area of freedom, security and justice without internal frontiers, in which the free movement of persons is ensured in conjunction with appropriate measures with respect to external border controls, asylum, immigration and the prevention and combating of crime.\n3. The Union shall establish an internal market. It shall work for the sustainable development of Europe based on balanced economic growth and price stability, a highly competitive social market economy, aiming at full employment and social progress, and a high level of protection and improvement of the quality of the environment. It shall promote scientific and technological advance.\n4. The Union shall establish an economic and monetary union whose currency is the euro.\n5. In its relations with the wider world, the Union shall uphold and promote its values and interests and contribute to the protection of its citizens.', part: 'Title I', chapter: null, section: null },
        { num: '4', title: 'Relations between the Union and Member States', content: '1. In accordance with Article 5, competences not conferred upon the Union in the Treaties remain with the Member States.\n2. The Union shall respect the equality of Member States before the Treaties as well as their national identities, inherent in their fundamental structures, political and constitutional, inclusive of regional and local self-government. It shall respect their essential State functions, including ensuring the territorial integrity of the State, maintaining law and order and safeguarding national security. In particular, national security remains the sole responsibility of each Member State.\n3. Pursuant to the principle of sincere cooperation, the Union and the Member States shall, in full mutual respect, assist each other in carrying out tasks which flow from the Treaties.', part: 'Title I', chapter: null, section: null },
        { num: '5', title: 'Principles of conferral, subsidiarity, and proportionality', content: '1. The limits of Union competences are governed by the principle of conferral. The use of Union competences is governed by the principles of subsidiarity and proportionality.\n2. Under the principle of conferral, the Union shall act only within the limits of the competences conferred upon it by the Member States in the Treaties to attain the objectives set out therein. Competences not conferred upon the Union in the Treaties remain with the Member States.\n3. Under the principle of subsidiarity, in areas which do not fall within its exclusive competence, the Union shall act only if and in so far as the objectives of the proposed action cannot be sufficiently achieved by the Member States, either at central level or at regional and local level, but can rather, by reason of the scale or effects of the proposed action, be better achieved at Union level.\n4. Under the principle of proportionality, the content and form of Union action shall not exceed what is necessary to achieve the objectives of the Treaties.', part: 'Title I', chapter: null, section: null },
        { num: '6', title: 'Fundamental rights', content: '1. The Union recognises the rights, freedoms and principles set out in the Charter of Fundamental Rights of the European Union of 7 December 2000, as adapted at Strasbourg, on 12 December 2007, which shall have the same legal value as the Treaties.\n2. The Union shall accede to the European Convention for the Protection of Human Rights and Fundamental Freedoms. Such accession shall not affect the Union\'s competences as defined in the Treaties.\n3. Fundamental rights, as guaranteed by the European Convention for the Protection of Human Rights and Fundamental Freedoms and as they result from the constitutional traditions common to the Member States, shall constitute general principles of the Union\'s law.', part: 'Title I', chapter: null, section: null },
        { num: '7', title: 'Suspension of Member State rights', content: '1. On a reasoned proposal by one third of the Member States, by the European Parliament or by the European Commission, the Council, acting by a majority of four fifths of its members after obtaining the consent of the European Parliament, may determine that there is a clear risk of a serious breach by a Member State of the values referred to in Article 2. Before making such a determination, the Council shall hear the Member State in question.\n2. The European Council, acting by unanimity on a proposal by one third of the Member States or by the Commission and after obtaining the consent of the European Parliament, may determine the existence of a serious and persistent breach by a Member State of the values referred to in Article 2.\n3. Where a determination under paragraph 2 has been made, the Council, acting by a qualified majority, may decide to suspend certain of the rights deriving from the application of the Treaties to the Member State in question, including the voting rights of the representative of the government of that Member State in the Council.', part: 'Title I', chapter: null, section: null },
        { num: '8', title: 'Relations with neighbouring countries', content: '1. The Union shall develop a special relationship with neighbouring countries, aiming to establish an area of prosperity and good neighbourliness, founded on the values of the Union and characterised by close and peaceful relations based on cooperation.\n2. For the purposes of paragraph 1, the Union may conclude specific agreements with the countries concerned.', part: 'Title I', chapter: null, section: null },
        // TITLE II — PROVISIONS ON DEMOCRATIC PRINCIPLES (Articles 9-12)
        { num: '9', title: 'Citizenship of the Union', content: 'In all its activities, the Union shall observe the principle of the equality of its citizens, who shall receive equal attention from its institutions, bodies, offices and agencies. Every national of a Member State shall be a citizen of the Union. Citizenship of the Union shall be additional to and not replace national citizenship.', part: 'Title II', chapter: null, section: null },
        { num: '10', title: 'Representative democracy', content: '1. The functioning of the Union shall be founded on representative democracy.\n2. Citizens are directly represented at Union level in the European Parliament. Member States are represented in the European Council by their Heads of State or Government and in the Council by their governments, themselves democratically accountable either to their national Parliaments, or to their citizens.\n3. Every citizen shall have the right to participate in the democratic life of the Union. Decisions shall be taken as openly and as closely as possible to the citizen.\n4. Political parties at European level contribute to forming European political awareness and to expressing the will of citizens of the Union.', part: 'Title II', chapter: null, section: null },
        { num: '11', title: 'Participatory democracy', content: '1. The institutions shall, by appropriate means, give citizens and representative associations the opportunity to make known and publicly exchange their views in all areas of Union action.\n2. The institutions shall maintain an open, transparent and regular dialogue with representative associations and civil society.\n3. The European Commission shall carry out broad consultations with parties concerned in order to ensure that the Union\'s actions are coherent and transparent.\n4. Not less than one million citizens who are nationals of a significant number of Member States may take the initiative of inviting the European Commission, within the framework of its powers, to submit any appropriate proposal on matters where citizens consider that a legal act of the Union is required for the purpose of implementing the Treaties (European Citizens\' Initiative).', part: 'Title II', chapter: null, section: null },
        { num: '12', title: 'Role of national Parliaments', content: 'National Parliaments contribute actively to the good functioning of the Union:\n(a) through being informed by the institutions of the Union and having draft legislative acts forwarded to them;\n(b) by seeing to it that the principle of subsidiarity is respected;\n(c) by taking part in the evaluation mechanisms for the implementation of the Union policies in the area of freedom, security and justice;\n(d) by taking part in the revision procedures of the Treaties;\n(e) by being notified of applications for accession to the Union;\n(f) by taking part in the inter-parliamentary cooperation between national Parliaments and with the European Parliament.', part: 'Title II', chapter: null, section: null },
        // TITLE III — PROVISIONS ON THE INSTITUTIONS (Articles 13-19)
        { num: '13', title: 'Institutional framework', content: '1. The Union shall have an institutional framework which shall aim to promote its values, advance its objectives, serve its interests, those of its citizens and those of the Member States, and ensure the consistency, effectiveness and continuity of its policies and actions.\nThe Union\'s institutions shall be: the European Parliament; the European Council; the Council; the European Commission; the Court of Justice of the European Union; the European Central Bank; the Court of Auditors.\n2. Each institution shall act within the limits of the powers conferred on it in the Treaties, and in conformity with the procedures, conditions and objectives set out in them. The institutions shall practice mutual sincere cooperation.', part: 'Title III', chapter: null, section: null },
        { num: '14', title: 'The European Parliament', content: '1. The European Parliament shall, jointly with the Council, exercise legislative and budgetary functions. It shall exercise functions of political control and consultation as laid down in the Treaties. It shall elect the President of the Commission.\n2. The European Parliament shall be composed of representatives of the Union\'s citizens. They shall not exceed seven hundred and fifty in number, plus the President. Representation of citizens shall be degressively proportional, with a minimum threshold of six members per Member State. No Member State shall be allocated more than ninety-six seats.\n3. The members of the European Parliament shall be elected for a term of five years by direct universal suffrage in a free and secret ballot.', part: 'Title III', chapter: null, section: null },
        { num: '15', title: 'The European Council', content: '1. The European Council shall provide the Union with the necessary impetus for its development and shall define the general political directions and priorities thereof. It shall not exercise legislative functions.\n2. The European Council shall consist of the Heads of State or Government of the Member States, together with its President and the President of the Commission. The High Representative of the Union for Foreign Affairs and Security Policy shall take part in its work.\n3. The European Council shall meet twice every six months, convened by its President.\n4. The European Council shall take its decisions by consensus, except where the Treaties provide otherwise.\n5. The European Council shall elect its President, by a qualified majority, for a term of two and a half years, renewable once.', part: 'Title III', chapter: null, section: null },
        { num: '16', title: 'The Council', content: '1. The Council shall, jointly with the European Parliament, exercise legislative and budgetary functions. It shall carry out policy-making and coordinating functions as laid down in the Treaties.\n2. The Council shall consist of a representative of each Member State at ministerial level, who may commit the government of the Member State in question and cast its vote.\n3. The Council shall act by a qualified majority except where the Treaties provide otherwise.\n6. The Council shall meet in different configurations. The General Affairs Council shall ensure consistency in the work of the different Council configurations.', part: 'Title III', chapter: null, section: null },
        { num: '17', title: 'The European Commission', content: '1. The Commission shall promote the general interest of the Union and take appropriate initiatives to that end. It shall ensure the application of the Treaties, and of measures adopted by the institutions pursuant to them. It shall oversee the application of Union law under the control of the Court of Justice. It shall execute the budget and manage programmes. It shall exercise coordinating, executive and management functions, as laid down in the Treaties. It shall ensure the Union\'s external representation. It shall initiate the Union\'s annual and multiannual programming.\n2. Union legislative acts may only be adopted on the basis of a Commission proposal, except where the Treaties provide otherwise.\n3. The Commission\'s term of office shall be five years. The members of the Commission shall be chosen on the ground of their general competence and European commitment.\n5. The President, the High Representative and the other members of the Commission shall be subject as a body to a vote of consent by the European Parliament.', part: 'Title III', chapter: null, section: null },
        { num: '18', title: 'High Representative for Foreign Affairs and Security Policy', content: '1. The European Council, acting by a qualified majority, with the agreement of the President of the Commission, shall appoint the High Representative of the Union for Foreign Affairs and Security Policy. The European Council may end his term of office by the same procedure.\n2. The High Representative shall conduct the Union\'s common foreign and security policy. He shall contribute by his proposals to the development of that policy, which he shall carry out as mandated by the Council. The same shall apply to the common security and defence policy.\n3. The High Representative shall preside over the Foreign Affairs Council.\n4. The High Representative shall be one of the Vice-Presidents of the Commission.', part: 'Title III', chapter: null, section: null },
        { num: '19', title: 'The Court of Justice of the European Union', content: '1. The Court of Justice of the European Union shall include the Court of Justice, the General Court and specialised courts. It shall ensure that in the interpretation and application of the Treaties the law is observed.\nMember States shall provide remedies sufficient to ensure effective legal protection in the fields covered by Union law.\n2. The Court of Justice shall consist of one judge from each Member State. It shall be assisted by Advocates-General.\nThe General Court shall include at least one judge per Member State.\n3. The Court of Justice shall, in accordance with the Treaties:\n(a) rule on actions brought by a Member State, an institution or a natural or legal person;\n(b) give preliminary rulings, at the request of courts or tribunals of the Member States, on the interpretation of Union law or the validity of acts adopted by the institutions;\n(c) rule in other cases provided for in the Treaties.', part: 'Title III', chapter: null, section: null },
        // TITLE IV — PROVISIONS ON ENHANCED COOPERATION (Article 20)
        { num: '20', title: 'Enhanced cooperation', content: '1. Member States which wish to establish enhanced cooperation between themselves within the framework of the Union\'s non-exclusive competences may make use of its institutions and exercise those competences by applying the relevant provisions of the Treaties, subject to the limits and in accordance with the procedures laid down in this Article and in Articles 326 to 334 of the Treaty on the Functioning of the European Union.\n2. The decision authorising enhanced cooperation shall be adopted by the Council as a last resort, when it has established that the objectives of such cooperation cannot be attained within a reasonable period by the Union as a whole, and provided that at least nine Member States participate in it.', part: 'Title IV', chapter: null, section: null },
        // TITLE V — GENERAL PROVISIONS ON THE UNION'S EXTERNAL ACTION AND SPECIFIC PROVISIONS ON THE COMMON FOREIGN AND SECURITY POLICY (Articles 21-46)
        { num: '21', title: 'Principles of external action', content: '1. The Union\'s action on the international scene shall be guided by the principles which have inspired its own creation, development and enlargement, and which it seeks to advance in the wider world: democracy, the rule of law, the universality and indivisibility of human rights and fundamental freedoms, respect for human dignity, the principles of equality and solidarity, and respect for the principles of the United Nations Charter and international law.\n2. The Union shall define and pursue common policies and actions, and shall work for a high degree of cooperation in all fields of international relations, in order to: (a) safeguard its values, fundamental interests, security, independence and integrity; (b) consolidate and support democracy, the rule of law, human rights and the principles of international law; (c) preserve peace, prevent conflicts and strengthen international security.', part: 'Title V', chapter: 'Chapter 1', section: null },
        { num: '22', title: 'Strategic interests and objectives', content: 'On the basis of the principles and objectives set out in Article 21, the European Council shall identify the strategic interests and objectives of the Union. Decisions of the European Council on the strategic interests and objectives of the Union shall relate to the common foreign and security policy and to other areas of the external action of the Union.', part: 'Title V', chapter: 'Chapter 1', section: null },
        { num: '23', title: 'CFSP principles', content: 'The Union\'s action on the international scene, pursuant to this Chapter, shall be guided by the principles, shall pursue the objectives of, and be conducted in accordance with, the general provisions laid down in Chapter 1.', part: 'Title V', chapter: 'Chapter 2', section: null },
        { num: '24', title: 'CFSP scope and procedures', content: '1. The Union\'s competence in matters of common foreign and security policy shall cover all areas of foreign policy and all questions relating to the Union\'s security, including the progressive framing of a common defence policy that might lead to a common defence. The common foreign and security policy is subject to specific rules and procedures. It shall be defined and implemented by the European Council and the Council acting unanimously, except where the Treaties provide otherwise. The adoption of legislative acts shall be excluded.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '25', title: 'CFSP instruments', content: 'The Union shall conduct the common foreign and security policy by: (a) defining the general guidelines; (b) adopting decisions defining: (i) actions to be undertaken by the Union; (ii) positions to be taken by the Union; (iii) arrangements for the implementation of the decisions referred to in points (i) and (ii); and (c) strengthening systematic cooperation between Member States in the conduct of policy.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '26', title: 'European Council role in CFSP', content: 'The European Council shall identify the Union\'s strategic interests, determine the objectives of and define general guidelines for the common foreign and security policy, including for matters with defence implications. It shall adopt the necessary decisions.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '27', title: 'High Representative role', content: 'The High Representative of the Union for Foreign Affairs and Security Policy shall contribute through his proposals to the development of the common foreign and security policy and shall ensure implementation of the decisions adopted by the European Council and the Council. He shall represent the Union for matters relating to the common foreign and security policy. He shall conduct political dialogue with third parties on the Union\'s behalf and shall express the Union\'s position in international organisations and at international conferences.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '28', title: 'Operational action', content: 'Where the international situation requires operational action by the Union, the Council shall adopt the necessary decisions. They shall lay down their objectives, scope, the means to be made available to the Union, if necessary their duration, and the conditions for their implementation.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '29', title: 'Union positions', content: 'The Council shall adopt decisions which shall define the approach of the Union to a particular matter of a geographical or thematic nature. Member States shall ensure that their national policies conform to the Union positions.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '30', title: 'Initiatives', content: 'Any Member State, the High Representative, or the High Representative with the Commission\'s support, may refer any question relating to the common foreign and security policy to the Council and may submit to it, respectively, initiatives or proposals.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '31', title: 'Voting in CFSP', content: 'Decisions under this Chapter shall be taken by the European Council and the Council acting unanimously, except where this Chapter provides otherwise. The adoption of legislative acts shall be excluded. When abstaining in a vote, any member of the Council may qualify its abstention by making a formal declaration (constructive abstention).', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '32', title: 'Consultation and convergence', content: 'Member States shall consult one another within the European Council and the Council on any matter of foreign and security policy of general interest in order to determine a common approach. Before undertaking any action on the international scene or entering into any commitment which could affect the Union\'s interests, each Member State shall consult the others within the European Council or the Council.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '33', title: 'Special representatives', content: 'The Council may, on a proposal from the High Representative of the Union for Foreign Affairs and Security Policy, appoint a special representative with a mandate in relation to particular policy issues. The special representative shall carry out his mandate under the authority of the High Representative.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '34', title: 'International organisations', content: 'Member States shall coordinate their action in international organisations and at international conferences. They shall uphold the Union\'s positions in such forums. The High Representative of the Union for Foreign Affairs and Security Policy shall organise this coordination.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '35', title: 'Diplomatic missions', content: 'The diplomatic and consular missions of the Member States and the Union delegations in third countries and international conferences, and their representations to international organisations, shall cooperate in ensuring that decisions defining Union positions and actions adopted pursuant to this Chapter are complied with and implemented.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '36', title: 'European Parliament and CFSP', content: 'The High Representative of the Union for Foreign Affairs and Security Policy shall regularly consult the European Parliament on the main aspects and the basic choices of the common foreign and security policy and the common security and defence policy and inform it of how those policies evolve.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '37', title: 'International agreements', content: 'The Union may conclude agreements with one or more States or international organisations in areas covered by this Chapter.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '38', title: 'Political and Security Committee', content: 'A Political and Security Committee shall monitor the international situation in the areas covered by the common foreign and security policy and contribute to the definition of policies by delivering opinions to the Council at the request of the Council or of the High Representative. It shall also monitor the implementation of agreed policies.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        // CSDP Section
        { num: '42', title: 'Common Security and Defence Policy', content: '1. The common security and defence policy shall be an integral part of the common foreign and security policy. It shall provide the Union with an operational capacity drawing on civilian and military assets. The Union may use them on missions outside the Union for peace-keeping, conflict prevention and strengthening international security in accordance with the principles of the United Nations Charter.\n2. The common security and defence policy shall include the progressive framing of a common Union defence policy. This will lead to a common defence, when the European Council, acting unanimously, so decides.\n7. If a Member State is the victim of armed aggression on its territory, the other Member States shall have towards it an obligation of aid and assistance by all the means in their power, in accordance with Article 51 of the United Nations Charter (mutual defence clause).', part: 'Title V', chapter: 'Chapter 2', section: 'Section 2' },
        { num: '43', title: 'Petersberg tasks', content: '1. The tasks referred to in Article 42(1), in the course of which the Union may use civilian and military means, shall include joint disarmament operations, humanitarian and rescue tasks, military advice and assistance tasks, conflict prevention and peace-keeping tasks, tasks of combat forces in crisis management, including peace-making and post-conflict stabilisation.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 2' },
        { num: '44', title: 'Task implementation', content: 'Within the framework of the decisions adopted in accordance with Article 43, the Council may entrust the implementation of a task to a group of Member States which are willing and have the necessary capability for such a task.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 2' },
        { num: '45', title: 'European Defence Agency', content: '1. The European Defence Agency, subject to the authority of the Council, shall have as its task to: (a) contribute to identifying the Member States\' military capability objectives and evaluating observance of the capability commitments given by the Member States; (b) promote harmonisation of operational needs; (c) propose multilateral projects; (d) support defence technology research; (e) contribute to identifying and implementing measures to strengthen the industrial and technological base of the defence sector.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 2' },
        { num: '46', title: 'Permanent Structured Cooperation', content: '1. Those Member States whose military capabilities fulfil higher criteria and which have made more binding commitments to one another in this area with a view to the most demanding missions shall establish permanent structured cooperation within the Union framework.\n2. Member States which wish to participate in the permanent structured cooperation and which fulfil the criteria and have made the commitments on military capabilities shall notify their intention to the Council and to the High Representative.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 2' },
        // TITLE VI — FINAL PROVISIONS (Articles 47-55)
        { num: '47', title: 'Legal personality', content: 'The Union shall have legal personality.', part: 'Title VI', chapter: null, section: null },
        { num: '48', title: 'Treaty revision', content: '1. The Treaties may be amended in accordance with an ordinary revision procedure. They may also be amended in accordance with simplified revision procedures.\n2. Ordinary revision procedure: The Government of any Member State, the European Parliament or the Commission may submit to the Council proposals for the amendment of the Treaties. A convention composed of representatives of the national Parliaments, of the Heads of State or Government of the Member States, of the European Parliament and of the Commission shall be convened.\n6. Simplified revision procedure: The European Council may adopt a decision amending all or part of the provisions of Part Three of the Treaty on the Functioning of the European Union (internal policies), acting by unanimity after consulting the European Parliament and the Commission.', part: 'Title VI', chapter: null, section: null },
        { num: '49', title: 'Accession', content: 'Any European State which respects the values referred to in Article 2 and is committed to promoting them may apply to become a member of the Union. The European Parliament and national Parliaments shall be notified of this application. The applicant State shall address its application to the Council, which shall act unanimously after consulting the Commission and after receiving the consent of the European Parliament.', part: 'Title VI', chapter: null, section: null },
        { num: '50', title: 'Voluntary withdrawal', content: '1. Any Member State may decide to withdraw from the Union in accordance with its own constitutional requirements.\n2. A Member State which decides to withdraw shall notify the European Council of its intention. In the light of the guidelines provided by the European Council, the Union shall negotiate and conclude an agreement with that State, setting out the arrangements for its withdrawal.\n3. The Treaties shall cease to apply to the State in question from the date of entry into force of the withdrawal agreement or, failing that, two years after the notification referred to in paragraph 2, unless the European Council, in agreement with the Member State concerned, unanimously decides to extend this period.', part: 'Title VI', chapter: null, section: null },
        { num: '51', title: 'Protocols and Annexes', content: 'The Protocols and Annexes to the Treaties shall form an integral part thereof.', part: 'Title VI', chapter: null, section: null },
        { num: '52', title: 'Territorial scope', content: '1. The Treaties shall apply to the Kingdom of Belgium, the Republic of Bulgaria, the Czech Republic, the Kingdom of Denmark, the Federal Republic of Germany, the Republic of Estonia, Ireland, the Hellenic Republic, the Kingdom of Spain, the French Republic, the Republic of Croatia, the Italian Republic, the Republic of Cyprus, the Republic of Latvia, the Republic of Lithuania, the Grand Duchy of Luxembourg, Hungary, the Republic of Malta, the Kingdom of the Netherlands, the Republic of Austria, the Republic of Poland, the Portuguese Republic, Romania, the Republic of Slovenia, the Slovak Republic, the Republic of Finland and the Kingdom of Sweden.\n2. The territorial scope of the Treaties is specified in Article 355 TFEU.', part: 'Title VI', chapter: null, section: null },
        { num: '53', title: 'Duration', content: 'This Treaty is concluded for an unlimited period.', part: 'Title VI', chapter: null, section: null },
        { num: '54', title: 'Ratification', content: 'This Treaty shall be ratified by the High Contracting Parties in accordance with their respective constitutional requirements. The instruments of ratification shall be deposited with the Government of the Italian Republic.', part: 'Title VI', chapter: null, section: null },
        { num: '55', title: 'Authentic texts and languages', content: '1. This Treaty, drawn up in a single original in the Bulgarian, Croatian, Czech, Danish, Dutch, English, Estonian, Finnish, French, German, Greek, Hungarian, Irish, Italian, Latvian, Lithuanian, Maltese, Polish, Portuguese, Romanian, Slovak, Slovenian, Spanish and Swedish languages, the texts in each of these languages being equally authentic, shall be deposited in the archives of the Government of the Italian Republic.\n2. This Treaty may also be translated into any other languages as determined by Member States.', part: 'Title VI', chapter: null, section: null },
    ];
    // We're missing 39, 40, 41 from the CFSP section — add them
    const additionalArticles = [
        { num: '39', title: 'Data protection in CFSP', content: 'The Council shall adopt a decision laying down the rules relating to the protection of individuals with regard to the processing of personal data by the Member States when carrying out activities which fall within the scope of this Chapter, and the rules relating to the free movement of such data.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '40', title: 'CFSP and other policies boundary', content: 'The implementation of the common foreign and security policy shall not affect the application of the procedures and the extent of the powers of the institutions laid down by the Treaties for the exercise of the Union competences referred to in Articles 3 to 6 of the TFEU. Similarly, the implementation of the policies listed in those Articles shall not affect the application of the procedures and the extent of the powers of the institutions laid down by the Treaties for the exercise of the Union competences under this Chapter.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
        { num: '41', title: 'CFSP expenditure', content: '1. Administrative expenditure which the implementation of this Chapter entails for the institutions shall be charged to the Union budget.\n2. Operating expenditure to which the implementation of this Chapter gives rise shall also be charged to the Union budget, except for such expenditure arising from operations having military or defence implications and cases where the Council acting unanimously decides otherwise.', part: 'Title V', chapter: 'Chapter 2', section: 'Section 1' },
    ];
    const allArticles = [...articles, ...additionalArticles];
    const insertMany = db.transaction((items) => {
        for (const a of items) {
            insertArticle.run(actId, a.num, a.title, a.content, a.part, a.chapter, a.section);
        }
    });
    insertMany(allArticles);
    console.log(`    TEU: ${allArticles.length} articles inserted.`);
}
